#include <stdio.h>
#include <stdlib.h>

int maxRectangleInHistogram(int *height, int n) {
    int *stack = (int*)malloc(n * sizeof(int));
    int top = -1, maxArea = 0, i = 0;
    while (i < n) {
        if (top == -1 || height[stack[top]] <= height[i]) {
            stack[++top] = i++;
        } else {
            int tp = stack[top--];
            int width = (top == -1) ? i : i - stack[top] - 1;
            int area = height[tp] * width;
            if (area > maxArea) maxArea = area;
        }
    }
    while (top != -1) {
        int tp = stack[top--];
        int width = (top == -1) ? i : i - stack[top] - 1;
        int area = height[tp] * width;
        if (area > maxArea) maxArea = area;
    }
    free(stack);
    return maxArea;
}

int main() {
    int T; scanf("%d", &T);
    while (T--) {
        int rows, cols; scanf("%d %d", &rows, &cols);
        int *height = (int*)calloc(cols, sizeof(int));
        int maxArea = 0;
        for (int i = 0; i < rows; ++i) {
            for (int j = 0; j < cols; ++j) {
                int val; scanf("%d", &val);
                if (val == 1) height[j] += 1; else height[j] = 0;
            }
            int cur = maxRectangleInHistogram(height, cols);
            if (cur > maxArea) maxArea = cur;
        }
        printf("%d\n", maxArea);
        free(height);
    }
    return 0;
}

