#include <bits/stdc++.h>
using namespace std;

int maxHistogram(const vector<int>& h) {
    stack<int> st;
    int maxA = 0, i = 0, n = h.size();
    while (i < n) {
        if (st.empty() || h[st.top()] <= h[i]) st.push(i++);
        else {
            int tp = st.top(); st.pop();
            int width = st.empty() ? i : i - st.top() - 1;
            maxA = max(maxA, h[tp] * width);
        }
    }
    while (!st.empty()) {
        int tp = st.top(); st.pop();
        int width = st.empty() ? i : i - st.top() - 1;
        maxA = max(maxA, h[tp] * width);
    }
    return maxA;
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; cin >> T;
    while (T--) {
        int rows, cols; cin >> rows >> cols;
        vector<int> height(cols, 0);
        int ans = 0;
        for (int i = 0; i < rows; ++i) {
            for (int j = 0; j < cols; ++j) {
                int v; cin >> v;
                height[j] = (v == 1) ? height[j] + 1 : 0;
            }
            ans = max(ans, maxHistogram(height));
        }
        cout << ans << '\n';
    }
    return 0;
}

